const e=`{% block sw_product_detail_specifications %} <div v-if="isLoading"> <sw-skeleton /> <sw-skeleton /> </div> <div v-else> {% block sw_product_detail_specifications_measurement %} <mt-card v-if="showProductCard('measurement') && !isDigitalProduct" class="sw-product-detail-specification__measurement" position-identifier="sw-product-detail-specifications-measurement" :title="$t('sw-product.specifications.cardTitleMeasurement')" > {% block sw_product_detail_specifications_measurement_content %} <sw-product-measurement-form :allow-edit="acl.can('product.editor')" /> {% endblock %} </mt-card> {% endblock %} {% block sw_product_detail_specifications_measures_packaging %} <mt-card v-if="showProductCard('selling_packaging') && !isDigitalProduct" class="sw-product-detail-specification__selling-packaging" position-identifier="sw-product-detail-specifications-measures-packaging" :title="$t('sw-product.specifications.cardTitleSellingPackaging')" > {% block sw_product_detail_specifications_measures_packaging_content %} <sw-product-packaging-form :show-setting-packaging="showModeSetting" :allow-edit="acl.can('product.editor')" /> {% endblock %} </mt-card> {% endblock %} {% block sw_product_detail_specifications_property %} <sw-product-properties v-show="showProductCard('properties')" /> {% endblock %} {% block sw_product_detail_specifications_essential_characteristics %} <mt-card v-show="showProductCard('essential_characteristics')" class="sw-product-detail-specification__essential-characteristics" position-identifier="sw-product-detail-specifications-essential-characteristics" :title="$t('sw-product.specifications.cardTitleEssentialCharacteristics')" > {% block sw_product_detail_specifications_essential_characteristics_content %} <sw-product-feature-set-form :allow-edit="acl.can('product.editor')" /> {% endblock %} </mt-card> {% endblock %} {% block sw_product_detail_specifications_custom_products %} {% endblock %} {% block sw_product_detail_specifications_custom_fields %} <mt-card v-show="showCustomFieldsCard" class="sw-product-detail-specification__custom-fields" position-identifier="sw-product-detail-specifications-custom-fields" :title="$t('sw-product.specifications.cardTitleCustomFields')" > {% block sw_product_detail_specifications_custom_fields_content %} <sw-custom-field-set-renderer show-custom-field-set-selection :entity="product" :parent-entity="parentProduct" :sets="customFieldSets" :disabled="!acl.can('product.editor')" /> {% endblock %} </mt-card> {% endblock %} </div> {% endblock %}`,i={template:e,inject:["acl","feature","repositoryFactory"],data(){return{showMediaModal:!1}},computed:{product(){return Shopware.Store.get("swProductDetail").product},parentProduct(){return Shopware.Store.get("swProductDetail").parentProduct},loading(){return Shopware.Store.get("swProductDetail").loading},isLoading(){return Shopware.Store.get("swProductDetail").isLoading},customFieldSets(){return Shopware.Store.get("swProductDetail").customFieldSets},showModeSetting(){return Shopware.Store.get("swProductDetail").showModeSetting},productStates(){return Shopware.Store.get("swProductDetail").productStates},productType(){return Shopware.Store.get("swProductDetail").productType},isDigitalProduct(){return this.productType==="digital"||this.productStates.includes("is-download")},customFieldsExists(){return!this.customFieldSets.length<=0},showCustomFieldsCard(){return this.showProductCard("custom_fields")&&!this.isLoading&&this.customFieldsExists}},methods:{showProductCard(t){return Shopware.Store.get("swProductDetail").showProductCard(t)}}};export{i as default};
